{
var density = Math.Max(1, GetInt(parameters, "density", 3));
        var brightness = GetFloat(parameters, "brightness", 0f);
        var contrast = GetFloat(parameters, "contrast", 0f);
        var safeWidth = GetFloat(parameters, "thickness", 0.15f);
        var invert = GetBool(parameters, "invert", false);

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);

        buffer.ParallelForEachPixel((x, y) =>
        {
            var u = x / (float)size;
            var v = y / (float)size;

            // 2x2 repeating cell (each cell is 0.5 x 0.5 in UV)
            var cellU = (u % 0.5f) / 0.5f; // 0..1 inside cell
            var cellV = (v % 0.5f) / 0.5f;
            var cellX = (int)MathF.Floor(u / 0.5f);
            var cellY = (int)MathF.Floor(v / 0.5f);
            var vertical = ((cellX + cellY) & 1) == 0;

            float vOut = 0f;

            // Parameters in cell-space: spacing between centers = 1/density
            var sigmaPerp = MathF.Max(0.0005f, safeWidth * 0.45f); // width across strip (in cell units)
            var capSigma = sigmaPerp * 1.15f;

            for (int oi = -2; oi <= 2; ++oi)
            {
                if (vertical)
                {
                    // centers along X within cell-space
                    var pos = cellU * density;
                    var nearest = MathF.Round(pos) + oi;
                    var centerX = nearest / (float)density; // in 0..1 cell-space

                    var dx = cellU - centerX; // perp distance in cell units
                    var dyCenter = cellV - 0.5f; // long axis centered

                    // Main narrow bar (no attenuation along length)
                    var ndPerp = dx / sigmaPerp;
                    var barMain = MathF.Exp(-0.5f * (ndPerp * ndPerp));

                    // Caps at top/bottom of the cell
                    var distTop = MathF.Sqrt(dx * dx + (cellV - 0f) * (cellV - 0f));
                    var distBot = MathF.Sqrt(dx * dx + (cellV - 1f) * (cellV - 1f));
                    var capTop = MathF.Exp(-0.5f * (distTop * distTop) / (capSigma * capSigma));
                    var capBot = MathF.Exp(-0.5f * (distBot * distBot) / (capSigma * capSigma));

                    var contrib = Math.Max(barMain, Math.Max(capTop, capBot));
                    if (contrib > vOut) vOut = contrib;
                }
                else
                {
                    // horizontal bars: centers along Y
                    var pos = cellV * density;
                    var nearest = MathF.Round(pos) + oi;
                    var centerY = nearest / (float)density;

                    var dy = cellV - centerY; // perp in cell units (for horizontal bar)
                    var dxCenter = cellU - 0.5f;

                    var ndPerp = dy / sigmaPerp;
                    var barMain = MathF.Exp(-0.5f * (ndPerp * ndPerp));

                    var distLeft = MathF.Sqrt(dy * dy + (cellU - 0f) * (cellU - 0f));
                    var distRight = MathF.Sqrt(dy * dy + (cellU - 1f) * (cellU - 1f));
                    var capLeft = MathF.Exp(-0.5f * (distLeft * distLeft) / (capSigma * capSigma));
                    var capRight = MathF.Exp(-0.5f * (distRight * distRight) / (capSigma * capSigma));

                    var contrib = Math.Max(barMain, Math.Max(capLeft, capRight));
                    if (contrib > vOut) vOut = contrib;
                }
            }

            // Peak softening / tonal shaping (similar to FibersNode)
            var widthFactorGlobal = Math.Clamp((safeWidth - 0.001f) / 1.5f, 0f, 1f);
            var peakSoftenBase = 0.45f;
            var peakSoften = peakSoftenBase + 0.5f * widthFactorGlobal;
            var powBase = 1.25f;
            var powExp = powBase + 0.9f * widthFactorGlobal;
            vOut = vOut * (1f - peakSoften) + MathF.Pow(vOut, powExp) * peakSoften;

            if (MathF.Abs(contrast) > 0.0001f)
            {
                var factor = 1f + contrast;
                vOut = (vOut - 0.5f) * factor + 0.5f;
            }

            vOut += brightness;
            vOut = Math.Clamp(vOut, 0f, 1f);

            var kneeStart = 0.88f - 0.25f * widthFactorGlobal;
            if (vOut > kneeStart)
            {
                var t = (vOut - kneeStart) / (1f - kneeStart);
                var easeExp = 1f + 2f * widthFactorGlobal;
                var eased = 1f - MathF.Pow(1f - t, easeExp);
                vOut = kneeStart + (1f - kneeStart) * eased;
            }

            if (invert) vOut = 1f - vOut;

            buffer.SetPixel(x, y, vOut, vOut, vOut, 1f);
        });

        return buffer;
}
